var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"아, 먼저 와 계신 분들이 있었네요.","JPN":"あ、先に使っている方がいたんですね。","ENG":"Oh, I see you were here first.","TWN":"啊，原來這裡有人先來了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"죄송해요. 전 조금 있다가 다시 올게요.","JPN":"邪魔してすみません。あとでまた来ます。","ENG":"Sorry. I'll come back later.","TWN":"對不起，我晚點再來吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"괜찮아요, 레이 선배!","JPN":"大丈夫ですよ、レイ先輩！","ENG":"It's okay, Ray!","TWN":"沒關係的，雷伊前輩！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"저희는 이제 시뮬레이터를 다 썼거든요.","JPN":"もうシミュレーターの使用は終わりました。","ENG":"We're all done with the simulator now.","TWN":"我們已經用完模擬器了。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"누, 누군가 했더니 미카였구나. 고마워.","JPN":"だ、誰かと思ったらミカだったんだね。ありがとう。","ENG":"O-oh, it's you, Mika. I appreciate it.","TWN":"原、原來是米卡啊。謝謝你。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 너 조금 전에 봤던......","JPN":"まって、あなたはさっき会った……","ENG":"Hang on... You're the one just before...","TWN":"等等。你是剛才的……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어라? 미나 너, 레이 선배랑 아는 사이야?","JPN":"あれ？　ミナちゃん、レイ先輩と知り合いなの？","ENG":"Huh? Do you already know Ray? He's an upper classman.","TWN":"哎呀？米娜你和雷伊前輩認識？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 조금은. 오늘 아침에 행정실로 가는 길을 알려 줬거든.","JPN":"まあ、少しだけ。今朝、事務室の場所を教えてもらったの。","ENG":"Sort of... He showed me the way to the registrar's office this morning.","TWN":"嗯，算是吧。今天早晨是他告訴我去辦公室的路。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 그때는 이름도 말 안 했네.","JPN":"そういえば自己紹介もしてなかったね。","ENG":"I guess I forgot to introduce myself then.","TWN":"說起來當時忘了自我介紹了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"유미나야. 앞으로 잘 부탁해, 레이 선배.","JPN":"ヤナギ・ミナだよ。これからよろしくね、レイ先輩。","ENG":"I'm Yoo Mina. Nice to meet you, Ray.","TWN":"我叫劉米娜。請多多關照，雷伊前輩。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"으응...... 나도 잘 부탁해.","JPN":"あ、うん……よろしくね。","ENG":"Yeah... Nice to meet you too.","TWN":"嗯……也請你多關照。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 선배는 여기 무슨 일이에요?","JPN":"ところで、先輩は何の用事ですか？","ENG":"What brings you here anyway?","TWN":"前輩來這裡是什麼事？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"설마...... 아직도?","JPN":"もしかして……また？","ENG":"Wait... You still haven't...","TWN":"難道……還沒？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"으, 응...... 또 실패했어.","JPN":"う、うん……また失敗した。","ENG":"N-no... I failed again.","TWN":"嗯……又失敗了。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어휴, 아직도 그러면 어떻게 해요? 선배가 아카데미를 다닌 지 몇 년째인데?","JPN":"ええーまたですか？　もうこのアカデミーに通って何年目でしたっけ？","ENG":"Aw, you still haven't cleared it? You've been attending the Academy for years now!","TWN":"哎，現在還沒成功可怎麼辦？前輩你來學院都幾年了？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"어쩔 수 없는걸. 싸움은 아무리 해도 적응이 안 되니까......","JPN":"仕方ないよ。戦いはいくらやっても慣れないから……","ENG":"Well, I can't help it. I just can't seem to get used to fighting...","TWN":"我也沒辦法啊。怎麼都不能適應打架……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미카, 둘이서 무슨 이야기를 하는 거야?","JPN":"ミカ、なんの話？","ENG":"What are you guys talking about?","TWN":"米卡，你們倆在說什麼呢？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 맞다. 미나 넌 처음 와서 모르겠구나.","JPN":"あ、ミナちゃんは知らないか。","ENG":"Oh, right. I guess you might not know since you're new.","TWN":"哦，對了。米娜你剛來，應該不知道吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};